def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-9
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 2:
            priority = (ratio ** 4) + (capacity % 3) * 2.5
            for k in range(1, int(capacity) + 2):
                if k % 2 == 0:
                    priority += np.sqrt(ratio * k) / (k + epsilon)
                else:
                    priority -= np.log(k + ratio + epsilon)
            if capacity % 2 == 1:
                priority *= 1.1
            else:
                priority /= 1.05
        elif 1 < ratio <= 2:
            priority = (ratio ** 2) * np.log(capacity + 1)
            for m in range(1, int(item) + 1):
                if m % 3 == 0:
                    priority += (m / (capacity + 1)) ** 2
                else:
                    priority -= m / (item + epsilon)
            priority = max(priority, 0)
        elif 0.3 < ratio <= 1:
            priority = -np.log(1 - ratio + epsilon)
            factor = 1
            for n in range(1, 5):
                factor *= (ratio + n / (capacity + 1))
                if factor > 5:
                    break
            priority *= factor
        else:
            total = 0
            for j in range(1, int(capacity) + 1):
                val = (ratio ** j) / (j + epsilon)
                if j % 2 == 0:
                    val *= -1
                total += val
            priority = abs(total) + 0.5
        if capacity < item:
            diff = (item - capacity)
            penalty = diff * 15
            for p in range(1, int(diff) + 1):
                if p % 2 == 0:
                    penalty += np.log(p + 1)
                else:
                    penalty -= p * 0.1
            penalty = max(penalty, 0)
            priority += penalty
        priorities[i] = priority
    return priorities
